transforms.result:
* {
    padding: 0;
    margin: 0;
    box-sizing: border-box;
    user-select: none
}

li {
    list-style-type: none
}

a {
    text-decoration: none;
    color: #fff
}

html {
    background: #000;
    height: 100%
}

.login1 {
    margin: 0 auto;
    height: 100%;
    position: relative;
    background: #000a13 url(/src/assets/css/login/bg.jpg) no-repeat top center;
    font-family: "PingFang SC", "Lantinghei SC", "Microsoft YaHei", "HanHei SC", "Helvetica Neue", "Open Sans", Arial, "Hiragino Sans GB", "微软雅黑", STHeiti, "WenQuanYi Micro Hei", SimSun, sans-serif
}

.loginbg {
    background-image: linear-gradient(300deg, #004491, #1e88e5);
    position: absolute;
    width: 100%;
    height: 50%;
    left: 0;
    top: 0;
    z-index: 0
}

.loginav {
    max-width: 1300px;
    height: 100%;
    margin: 0 auto;
    z-index: 10;
    box-shadow: 0 0 30px rgba(0, 0, 0, .1);
    display: flex;
    align-items: center;
    justify-content: center;
    padding-bottom: 5%
}

.loginbox {
    padding: 30px 0 50px 0;
    width: 1240px;
    height: 605px;
    padding: 30px 50px;
    background: url(/src/assets/css/login/bg2.png) no-repeat center center;
    background-size: 100%;
    flex-shrink: 0;
    position: relative;
    z-index: 100
}

.logininput {
    width: 500px;
    margin: 0 auto;


}

.logininput .forminput {
    border: 1px solid #9ce7ff;
    border-radius: 5px;
    font-family: "PingFang SC", "Lantinghei SC", "Microsoft YaHei", "HanHei SC", "Helvetica Neue", "Open Sans", Arial, "Hiragino Sans GB", "微软雅黑", STHeiti, "WenQuanYi Micro Hei", SimSun, sans-serif;
    display: block;
    padding-left: 50px;
    font-size: 18px;
    color: #fff;
    width: 100%;
    line-height: 52px;
    outline: 0;
    text-indent: 1px;
    background: rgba(32, 163, 245, .1)
}

input::input-placeholder {
    color: #fff
}

::-webkit-input-placeholder {
    color: #fff
}

.flex1 {
    display: flex;
    justify-content: space-between;
    align-items: center
}

.flex1 label {
    color: #fff;
    display: flex;
    align-items: center
}

.logininput > li {
    display: block;
    padding: 12px 0;
    position: relative
}

.logininput li > i {
    position: absolute;
    height: 100%;
    left: 15px;
    top: 0;
    display: flex;
    align-items: center
}

.btn-primary {
    background: #20a3f5;
    display: block;
    text-align: center;
    color: #fff;
    line-height: 64px;
    font-size: 32px;
    transition: all .5s;
    border-radius: 6px
}

.btn-primary:hover {
    background: #137bd6
}

.copyright {
    position: fixed;
    width: 100%;
    left: 0;
    bottom: 10px;
    text-align: center;
    color: rgba(0, 0, 0, .5);
    font-size: 12px;
    text-shadow: 1px 1px 2px rgba(0, 0, 0, .5)
}

.yzmimg {
    position: absolute;
    right: 0;
    background: #fff;
    width: 130px;
    height: 52px;
    top: 13px;
    border: 1px solid #9ce7ff;
    border-radius: 5px
}

.logintit {
    padding: 20px 0;
    font-size: 24px;
    display: flex;
    justify-content: center
}

.logintit span {
    border-bottom: 3px solid #fff;
    padding-bottom: 10px;
    color: #fff;
    font-size: 24px
}

.logo {
    width: 100%;
    left: 0;
    display: flex;
    justify-content: center;
    font-size: 68px;
    margin-top: -60px;
    font-weight: bold;
    letter-spacing: 2px;
    background: linear-gradient(90deg, #04a8f0, #46daff, #4177ed, #04a8f0, #46daff, #4177ed, #04a8f0, #46daff, #4177ed);
    background-size: cover;
    -webkit-background-clip: text;
    background-clip: text;
    -webkit-text-fill-color: transparent;
    text-fill-color: transparent;
    font-family: "Microsoft YaHei", "HanHei SC", "Helvetica Neue", "Open Sans", Arial, "Hiragino Sans GB", "微软雅黑", STHeiti, "WenQuanYi Micro Hei", SimSun, sans-serif
}

.boxall {
    transform: scale(.5);
    opacity: 0;
    animation: shows 1.5s forwards
}

@keyframes shows {
    to {
        transform: scale(1);
        opacity: 1
    }
}

.aui-checkbox, input[type=radio] {
    width: 24px;
    height: 24px;
    background: rgba(32, 163, 245, .1);
    border: solid 2px rgba(32, 163, 245, .5);
    margin: 0;
    padding: 0;
    position: relative;
    cursor: default;
    -webkit-appearance: none;
    -webkit-user-select: none;
    user-select: none;
    -webkit-transition: background-color ease .1s;
    transition: background-color ease .1s;
    flex-shrink: 0;
    border-radius: 0
}

.aui-checkbox, input[type=radio] {
    margin: 0 3px 0 0 !important;
    position: relative
}

.aui-checkbox:checked, input[type=radio]:checked {
    text-align: center;
    background-clip: padding-box
}

.aui-checkbox:checked:after, .aui-checkbox:checked:before, input[type=radio]:checked:after, input[type=radio]:checked:before {
    content: '';
    width: 10px;
    height: 5px;
    position: absolute;
    top: 50%;
    left: 50%;
    margin-left: -6px;
    margin-top: -5px;
    background: 0;
    border: 2px solid #439aff;
    border-top: 0;
    border-right: 0;
    z-index: 2;
    -webkit-border-radius: 0;
    border-radius: 0;
    -webkit-transform: rotate(-45deg);
    transform: rotate(-45deg)
}

.aui-checkbox:disabled, input[type=radio]:disabled {
    background-color: #f5f5f;
    border: solid 1px #ddd
}

.aui-checkbox:disabled:after, .aui-checkbox:disabled:before, input[type=radio]:disabled:after, input[type=radio]:disabled:before {
    content: '';
    width: .5rem;
    height: .3rem;
    position: absolute;
    top: 50%;
    left: 50%;
    margin-left: -.25rem;
    margin-top: -.4rem;
    background: 0;
    border: 1px solid #fff;
    border-top: 0;
    border-right: 0;
    z-index: 2;
    -webkit-border-radius: 0;
    border-radius: 0;
    -webkit-transform: rotate(-45deg);
    transform: rotate(-45deg)
}

input[type="radio"] {
    border-radius: 20px
}

input {
    outline: none !important
}

.forget {
    padding: 15px 0;
    width: 500px;
    margin: 0 auto
}

@media (max-width: 1200px) {
    .loginbox {
        width: 100%;
        height: auto;
        background: 0;
        padding: 0 15px
    }

    .logininput {
        width: 80%;
        margin: 0 auto;
    }

    .forget {
        width: auto
    }

    .logo {
        font-size: 36px
    }

    .logintit span {
        font-size: 16px
    }

    .btn-primary {
        font-size: 18px;
        line-height: 52px
    }

    .loginav {
        backdrop-filter: blur(6px)
    }
}

.el-row {
  align-items: center;
}

:deep(.el-form-item__label), :deep(.el-checkbox__label), button.is-link {
  color: var(--star-horse-white) !important;
}

